function showPopup(message, closeAfter,bg) {
	const popup = document.getElementById('popup');
	popup.textContent = message;
	popup.style.opacity = '1';
	popup.style.backgroundColor = bg;

	setTimeout(() => {
		popup.style.opacity = '0';
	}, closeAfter); // 2秒后自动消失
}

function send_http(url){
	getResponse(url, function(responseText) {
		if (responseText == "OK") {
			showPopup("Success!", 1500, "#02a601");
		} else{
			if (url.includes('/wifisave')) {
				showPopup("WiFi info saved, will reboot to connect!", 3000, "#02a601");
			}else{
				showPopup("Failed.", 2000, "#dc0d04");
			}
		} 
	});
}
